#include "MRFMoveVentsDlg.h"
#include "CATDlgFrame.h"
#include "CATApplicationFrame.h"
#include "CATDlgMultiList.h"
#include "CATDialog.h"
#include "CATDlgGridConstraints.h"
#include "CATDlgContextualMenu.h"
#include "CATDlgPushItem.h"
#include "CATListOfDouble.h"

//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFMoveVentsDlg::MRFMoveVentsDlg(CATDialog* iParent, const CATString& iName) :
	CATDlgDialog(iParent,
		iName,
		CATDlgGridLayout |
		CATDlgWndModal |
		CATDlgWndAPPLY |
		CATDlgWndCANCEL |
		CATDlgWndPREVIEW |
		CATDlgWndNoResize
	)
{
	_pMainFrame = NULL;
	_pMoveVentsMultiList = NULL;
	_pCtxMenu = NULL;

	_pMainFrame = new CATDlgFrame(this, (const char*)"MainFrame", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
	_pMainFrame->SetGridConstraints(0, 0, 5, 1, CATGRID_4SIDES);

	SetVisibility(CATDlgHide);
	SetCANCELTitle("Close");
	SetAPPLYTitle("Move Vents");
	SetPREVIEWTitle("Reset");
}

//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFMoveVentsDlg::~MRFMoveVentsDlg()
{
	_pMainFrame = NULL;
	_pMoveVentsMultiList = NULL;
	_pCtxMenu = NULL;
}

void MRFMoveVentsDlg::BuildMultiList(int iNBRow, int iNBColumn)
{
	CATDlgFrame * pMultiListFrame = new CATDlgFrame(_pMainFrame, (const char*)"Move Vents based on U & V values on Reference Surface", CATDlgGridLayout);
	pMultiListFrame->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	_pMoveVentsMultiList = new CATDlgMultiList(pMultiListFrame, (const char*)"MoveVents");
	_pMoveVentsMultiList->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	_pCtxMenu = new CATDlgContextualMenu(_pMoveVentsMultiList, CATString("CtxMenuMinDistResults"), CATDlgCtxEmpty);

	_pMoveVentsMultiList->SetVisibleColumnCount(iNBColumn);

	if (iNBRow <= 10)
		_pMoveVentsMultiList->SetVisibleLineCount(iNBRow);
	else
		_pMoveVentsMultiList->SetVisibleLineCount(10);

	CATUnicodeString strHeader[5];
	strHeader[0] = "   Vent   ";
	strHeader[1] = "  U  ";
	strHeader[2] = "V";
	strHeader[3] = "Delta U";
	strHeader[4] = "Delta V";

	_pMoveVentsMultiList->SetColumnTitles(5, strHeader);

	_pMoveVentsMultiList->SetColumnEditable(3, TRUE);
	_pMoveVentsMultiList->SetColumnEditable(4, TRUE);
}



